import React, { useState } from 'react';
import './index.css';
import Landing from './pages/Landing';
import Dashboard from './pages/Dashboard';
import Goals from './pages/Goals';
import Commit from './pages/Commit';
import Calendar from './pages/Calendar';

type Page = 'landing' | 'dashboard' | 'goals' | 'commit' | 'calendar';

function NavIcon({ name }: { name: string }) {
  const icons: Record<string, JSX.Element> = {
    dashboard: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/>
        <rect x="3" y="14" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/>
      </svg>
    ),
    goals: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="4"/><circle cx="12" cy="12" r="1" fill="currentColor"/>
      </svg>
    ),
    commit: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="9"/>
        <path d="M12 7v5l3 3"/>
      </svg>
    ),
    calendar: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/>
        <circle cx="8" cy="15" r="1" fill="currentColor"/><circle cx="12" cy="15" r="1" fill="currentColor"/><circle cx="16" cy="15" r="1" fill="currentColor"/>
      </svg>
    ),
  };
  return icons[name] || null;
}

export default function App() {
  const [page, setPage] = useState<Page>('landing');

  const navItems = [
    { id: 'dashboard', label: 'ホーム' },
    { id: 'goals', label: '目標' },
    { id: 'commit', label: 'コミット' },
    { id: 'calendar', label: 'カレンダー' },
  ] as const;

  if (page === 'landing') {
    return <Landing onStart={() => setPage('dashboard')} />;
  }

  return (
    <div>
      {page === 'dashboard' && <Dashboard onNavigate={(p) => setPage(p as Page)} />}
      {page === 'goals' && <Goals />}
      {page === 'commit' && <Commit />}
      {page === 'calendar' && <Calendar />}

      <nav className="bottom-nav">
        {navItems.map(item => (
          <button
            key={item.id}
            className={page === item.id ? 'active' : ''}
            onClick={() => setPage(item.id)}
          >
            <NavIcon name={item.id} />
            {item.label}
          </button>
        ))}
      </nav>
    </div>
  );
}
